sql:
SELECT activity_description, data_quality_assessment
FROM lci_data
WHERE data_quality_assessment LIKE '%Good%' AND year = 'v3.4 in 2017';

SELECT data_id, input_description, activity_description, activity_type, input_unit, output_description, output_unit, data_source_id, geography_id, year, data_quality_assessment, data_quality_score, data_collection_method
FROM lci_data
WHERE data_id = 1;

SELECT data_id, ABS(data_quality_score) AS absolute_quality_score, LENGTH(data_quality_assessment) AS quality_assessment_length
FROM lci_data
ORDER BY ABS(data_quality_score) DESC, data_id ASC;

SELECT dimension_name, description
FROM data_quality_dimensions
WHERE dimension_id = 1;

SELECT dimension_name, weight
FROM data_quality_dimensions
WHERE weight = 20;

SELECT * 
FROM lci_data
ORDER BY year DESC;

external_knowledge:
- "regions" refers to 'geography_name';
- "ecoinvent umbrella" refers to the data source named 'ecoinvent';
- "threshold of mediocrity" is a metaphor for the quality score greater than 2;
- "harvest of 2022" refers to the data collected in the year 2022;
- "abundant" refers to the count of records;
- "golden yield" refers to the average data quality score.

sql:
SELECT activity_type, AVG(data_quality_score) AS average_data_quality_score
FROM lci_data
GROUP BY activity_type;
